const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const body=($('Webhook').first().json.body)||{};
const country=String(body.country||'').trim();
let kws=[];
try{ const resp=$('Generate').first().json; const txt=(resp&&resp.content&&resp.content[0]&&resp.content[0].text)||''; const o=JSON.parse(String(txt).replace(/```json/gi,'').replace(/```/g,'').trim()); kws=Array.isArray(o.keywords)?o.keywords:[]; }catch(e){}
let created=0, dup=0;
for(const k of kws){ const q=String((k&&k.q)||'').trim(); if(!q) continue; const lang=String((k&&k.lang)||'').trim().slice(0,5);
  try{ await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/search_keywords/records',headers:pbH,body:{keyword:q,country,lang,status:'pending',attempts:0},json:true}); created++; }
  catch(e){ dup++; } }
return [{json:{country,generated:kws.length,created,duplicates:dup}}];
